vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = (vUvOriginal-0.62) * uAspect.xy;

vec2 uv6 = uv1;
float z = q30 +0.58*q27*length(uv1);
vec2 d = normalize(uv1);

vec2 rs = clamp(tan(z)*d,-8,8);
rs = multiply(rs+0.1,mat2(_qa));

if (q28 ==1) {rs *= cos(uv1.yx*11) ;}

vUv += rs/30;


uv6 = (vUv-0.51);
